import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.directory.*;
import java.util.HashMap;
import java.util.Map;

public class LdapSearch {

    public static Map<String, String> searchUserByUsername(String ldapUrl, String baseDn, String username) {
        Map<String, String> userAttributes = new HashMap<>();

        try {
            // Set up the environment for creating the initial context
            Hashtable<String, String> env = new Hashtable<>();
            env.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
            env.put(Context.PROVIDER_URL, ldapUrl);

            // Create the initial context
            DirContext ctx = new InitialDirContext(env);

            // Set up the search controls
            SearchControls constraints = new SearchControls();
            constraints.setSearchScope(SearchControls.SUBTREE_SCOPE);
            String[] attrIDs = {"mail", "cn", "department"};
            constraints.setReturningAttributes(attrIDs);

            // Perform the search
            String filter = "(uid=" + username + ")";
            NamingEnumeration<SearchResult> results = ctx.search(baseDn, filter, constraints);

            // Process the results
            if (results.hasMore()) {
                SearchResult result = results.next();
                Attributes attributes = result.getAttributes();

                userAttributes.put("email", attributes.get("mail") != null ? (String) attributes.get("mail").get() : "");
                userAttributes.put("full name", attributes.get("cn") != null ? (String) attributes.get("cn").get() : "");
                userAttributes.put("department", attributes.get("department") != null ? (String) attributes.get("department").get() : "");
            }

            // Close the context
            ctx.close();
        } catch (Exception e) {
            e.printStackTrace();
        }

        return userAttributes;
    }
}